const { DEVICE_TYPES } = require('../constants/device');
const { getFileDeviceType } = require('./file/device');
const { getFilePageMember } = require('./file/page-member');
const { getFileBasename } = require('./file/path-detail');

/**
 * @typedef { keyof DEVICE_TYPES } DeviceType
 *
 * @typedef { object } DuplicatedFilesByExtensionLogParams
 * @property { string[] } files - Duplicated files
 * @property { string } pageLogPortion - Log portion with the page identifier (ex. route or statusError)
 * @property { string } filesPageMember - Page member the files represent
 * @property { DeviceType } [filesDeviceType=DEVICE_TYPES.base] - Device type to which the files belong
 *
 * @typedef { object } ThrowDuplicatedFilesErrorParams
 * @property { string } currentFile - Full path of current file being analized
 * @property { string } previousFile - Full path of the file previously processed
 * @property { string } baseDir - Base directory
 * @property { string } pageLogPortion - Log portion with the page identifier (ex. route or statusError)
 *
 * @typedef { object } ThrowDuplicatedPageParams - Entity with the duplicated data
 * @property { string } currentFile - Full path of current file being analized
 * @property { string } previousFile - Full path of the file previously processed
 * @property { string } baseDir - Base directory
 * @property { string } pageLogPortion - Log portion with the page identifier (ex. route or statusError)
 *
 * @typedef { {
 *  [route:string]: string[]
 * } } DuplicatedNavigablePageFilesByRoute
 *
 * @typedef { {
 *  [statusError:string]: string[]
 * } } DuplicatedHttpErrorPageFilesByRoute
 */

/**
 * @param { DuplicatedNavigablePageFilesByRoute | undefined } duplicatedNavigablePages - Duplicated files by page route
 * @param { DuplicatedHttpErrorPageFilesByRoute | undefined } duplicatedHttpErrorPages - Duplicated files by page status error
 * @returns { string } Log message
 */
const getDuplicatedPagesLog = (
  duplicatedNavigablePages,
  duplicatedHttpErrorPages,
) => {
  const duplicatedMsg = Object.keys(duplicatedNavigablePages || {}).reduce(
    (logAcc, route) =>
      `${logAcc}\n- For ${route} page:\n\t* ${duplicatedNavigablePages[
        route
      ].join('\n\t* ')}\n`,
    'Ambiguous definition detected for certain pages. It is not possible to define an ' +
      'index file inside a folder of the same type and name ' +
      'as another file. Files in conflict:\n',
  );

  return Object.keys(duplicatedHttpErrorPages || {}).reduce(
    (logAcc, statusError) =>
      `${logAcc}\n- For ${statusError} error page:\n\t* ${duplicatedHttpErrorPages[
        statusError
      ].join('\n\t* ')}\n`,
    duplicatedMsg,
  );
};

/**
 * @param { string[] } files - Duplicated files
 * @param { string } pageLogPortion - Log portion with the page identifier (ex. route or statusError)
 * @returns { string } Log message
 */
const getDuplicatedFilesByIndexNamingConventionLog = (files, pageLogPortion) =>
  `Ambiguous definition for ${pageLogPortion}. It is not possible to define a ` +
  'view on an index file inside a folder with the same name ' +
  'as another view file. Files in conflict:\n' +
  `\t* ${files.join('\n\t* ')}\n`;

/**
 * @param { DuplicatedFilesByExtensionLogParams } duplicatedFilesLogParams
 * @returns { string } Log message
 */
const getDuplicatedFilesByExtensionLog = ({
  files,
  pageLogPortion,
  filesPageMember,
  filesDeviceType,
}) =>
  `Ambiguous ${filesPageMember} file definition for ${pageLogPortion}` +
  `${
    filesDeviceType && filesDeviceType !== DEVICE_TYPES.base
      ? ` and ${filesDeviceType} device`
      : ''
  }. ` +
  'It is not possible to assign the same file name with different ' +
  `${filesPageMember} extensions. Please check the file definition ` +
  'convention for Nordic Page. Files in conflict:\n' +
  `\t* ${files.join('\n\t* ')}\n`;

/**
 * Throws duplicated page by file type extension or index naming convention.
 * @param { ThrowDuplicatedPageParams } throwDuplicatedPageParams
 */
const throwDuplicatedPage = ({
  currentFile,
  previousFile,
  baseDir,
  pageLogPortion,
}) => {
  const currentFileFullPath = `${baseDir}/${currentFile}`;
  const files = [previousFile, currentFileFullPath];

  let message;

  // File with same path but different extension (ex. test.js, test.ts)
  if (getFileBasename(currentFileFullPath) === getFileBasename(previousFile)) {
    const filesPageMember = getFilePageMember(currentFile);
    const filesDeviceType = getFileDeviceType(currentFile);

    if (!filesPageMember || !filesDeviceType) {
      return;
    }

    message = getDuplicatedFilesByExtensionLog({
      files,
      filesPageMember,
      filesDeviceType,
      pageLogPortion,
    });
  } else {
    // Files with same route (ex. item.js, item/index.js)
    message = getDuplicatedFilesByIndexNamingConventionLog(
      files,
      pageLogPortion,
    );
  }

  throw new Error(message);
};

module.exports = {
  getDuplicatedPagesLog,
  getDuplicatedFilesByExtensionLog,
  getDuplicatedFilesByIndexNamingConventionLog,
  throwDuplicatedPage,
};
